def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' not in line:
            continue
        k, v = line.split(':', 1)
        k = k.strip().lower()
        v = v.strip().lower()
        if k in ('cap', 'rate'):
            out[k] = int(v) if v.lstrip('-').isdigit() else 0
        elif k == 'scrubber':
            out[k] = v in ('on', 'true', 'yes', '1', 'engaged')
    return out
